  - {kind: skill, ref: skills/run-dev-graph-schedule, tier: core}
  - {kind: skill, ref: skills/run-dev-graph-status, tier: core}
  - {kind: skill, ref: skills/run-dev-graph-system-spec, tier: core}
  - {kind: agent, ref: agents/dev-graph-integrity-auditor.md, tier: core}
  - {kind: agent, ref: agents/dev-graph-sync-conflict-verifier.md, tier: core}
  - {kind: agent, ref: agents/dev-graph-requirements-verifier.md, tier: core}
  - {kind: agent, ref: agents/dev-graph-parallel-safety-verifier.md, tier: core}
  - {kind: command, ref: commands/dev-graph.md, tier: core}
  - {kind: hook, ref: "hook:PreToolUse/guard-graph-schema", tier: core}
  - {kind: hook, ref: "hook:SessionStart/reconcile-task-lifecycle", tier: core}
  - {kind: hook, ref: "hook:PostToolUse/reconcile-task-lifecycle", tier: core}
  - {kind: hook, ref: "hook:TaskCompleted/reconcile-task-lifecycle", tier: core}
  - {kind: script, ref: scripts/resolve-repo-context.py, tier: core}
  - {kind: script, ref: scripts/validate-graph-schema.py, tier: core}
  - {kind: script, ref: scripts/gh-bridge.py, tier: core}
  - {kind: script, ref: scripts/bd-bridge.py, tier: core}
  - {kind: script, ref: scripts/manage-worktree-lease.py, tier: core}
  - {kind: script, ref: scripts/reconcile-github-lifecycle.py, tier: core}
  - {kind: script, ref: scripts/render-graph-html.py, tier: core}
  - {kind: script, ref: scripts/schedule-graph.py, tier: core}
  - {kind: script, ref: scripts/status-graph.py, tier: core}
  - {kind: script, ref: scripts/sync-graph.py, tier: core}
  - {kind: script, ref: scripts/upsert-node.py, tier: core}
  - {kind: script, ref: scripts/register-package.py, tier: core}

internal_support:
  - ref: scripts/_common.py
    owners: [C11, C12, C13, C16, C24, C26, C27, C28, C29]
    purpose: top-level capability ではなく、plugin-root scripts が共有する内部 runtime helper
  - ref: scripts/node_transaction.py
    owners: [C02, C05, C11, C15]
    purpose: nodeのWAL recoveryとread-only consumerのpending transaction fail-closed検査

