  - {from: commands/dev-graph.md, to: skills/run-dev-graph-node, type: calls}
  - {from: commands/dev-graph.md, to: skills/run-dev-graph-sync, type: calls}
  - {from: commands/dev-graph.md, to: skills/run-dev-graph-render, type: calls}
  - {from: commands/dev-graph.md, to: skills/run-dev-graph-schedule, type: calls}
  - {from: commands/dev-graph.md, to: skills/run-dev-graph-status, type: calls}
  - {from: commands/dev-graph.md, to: scripts/manage-worktree-lease.py, type: calls}
  - {from: skills/run-dev-graph-decompose, to: skills/run-dev-graph-node, type: calls}
