  - {from: skills/run-dev-graph-status, to: scripts/validate-graph-schema.py, type: calls}
  - {from: skills/run-dev-graph-status, to: scripts/status-graph.py, type: calls}
  - {from: skills/run-dev-graph-sync, to: scripts/resolve-repo-context.py, type: calls}
  - {from: skills/run-dev-graph-sync, to: scripts/sync-graph.py, type: calls}
  - {from: skills/run-dev-graph-sync, to: scripts/gh-bridge.py, type: calls}
  - {from: skills/run-dev-graph-sync, to: scripts/bd-bridge.py, type: calls}
  - {from: skills/run-dev-graph-sync, to: scripts/reconcile-github-lifecycle.py, type: calls}
  - {from: skills/run-dev-graph-sync, to: scripts/validate-graph-schema.py, type: calls}
  - {from: skills/run-dev-graph-sync, to: scripts/manage-worktree-lease.py, type: calls}
  - {from: skills/run-dev-graph-render, to: scripts/render-graph-html.py, type: calls}
  - {from: skills/run-dev-graph-schedule, to: scripts/schedule-graph.py, type: calls}
